#include <stdio.h>

int main(){

    int numero1 = 4, numero2 = 2, resultado;

    resultado = 10;
    printf("Resultado: %d\n", resultado);

    resultado +=20;
    printf("Resultado: %d\n", resultado);

    numero1 *= numero2;
    printf("Resultado: %d\n", numero1);

    resultado /= 6;
    printf("Resultado: %d\n", resultado);

    resultado -= 2;
    printf("Resultado: %d\n", resultado);



}